#!/usr/bin/env node
/**
 * Reads all .sql migration files from migrations/ and generates
 * packages/core/src/migrations-embedded.ts with the SQL inlined.
 *
 * This allows compiled binaries (bun build --compile) to access
 * migrations without filesystem reads at runtime.
 */
import { readdirSync, readFileSync, writeFileSync } from "node:fs"
import { resolve, dirname, join } from "node:path"
import { fileURLToPath } from "node:url"

const __dirname = dirname(fileURLToPath(import.meta.url))
const ROOT = resolve(__dirname, "..")
const MIGRATIONS_DIR = join(ROOT, "migrations")
const OUTPUT = join(ROOT, "packages/core/src/migrations-embedded.ts")

const files = readdirSync(MIGRATIONS_DIR)
  .filter(f => f.endsWith(".sql"))
  .sort()

const entries = files.map(filename => {
  const match = filename.match(/^(\d{3})_(.+)\.sql$/)
  if (!match) return null

  const version = parseInt(match[1], 10)
  const description = match[2].replace(/_/g, " ")
  const sql = readFileSync(join(MIGRATIONS_DIR, filename), "utf-8")

  return { version, description, sql }
}).filter(Boolean)

const code = `/* eslint-disable tx/no-inline-sql */
/**
 * Auto-generated by scripts/bundle-migrations.js — DO NOT EDIT.
 *
 * Contains all migration SQL inlined as string constants for use in
 * compiled binaries where filesystem access is unavailable.
 */
import type { Migration } from "./services/migration-service.js"

export const EMBEDDED_MIGRATIONS: readonly Migration[] = ${JSON.stringify(entries, null, 2)}
`

writeFileSync(OUTPUT, code, "utf-8")
console.log(`Generated ${entries.length} embedded migrations → ${OUTPUT}`)
